import * as fs from 'fs';
import * as path from 'path';
import * as yaml from 'js-yaml';

interface Link {
  name: string;
  url: string;
  private?: boolean;
  tags?: string[];
  description?: string;
}

interface Category {
  category: string;
  description?: string;
  links: Link[];
}

interface Config {
  title?: string;
  categories: Category[];
}

type InputRecord = Record<string, unknown>;
type ParseIssue = { path: string; message: string };

const RESERVED_ROOT_KEYS = new Set(['title', 'name', 'description', 'links']);
const CATEGORY_CONTAINER_KEYS = ['categories', 'sections', 'projects', 'portals', 'groups'];
const CATEGORY_NAME_KEYS = ['category', 'name', 'title', 'section', 'project', 'group'];
const CATEGORY_DESCRIPTION_KEYS = ['description', 'desc', 'details', 'note'];
const LINK_COLLECTION_KEYS = ['links', 'items', 'entries', 'bookmarks'];
const LINK_NAME_KEYS = ['name', 'title', 'label'];
const LINK_URL_KEYS = ['url', 'href', 'link', 'to'];
const LINK_DESCRIPTION_KEYS = ['description', 'desc', 'details', 'note'];
const ROOT_LINKS_CATEGORY = 'Links';

const isRecord = (value: unknown): value is InputRecord =>
  typeof value === 'object' && value !== null && !Array.isArray(value);

const getFirstString = (record: InputRecord, keys: string[]): string | undefined => {
  for (const key of keys) {
    const value = record[key];
    if (typeof value === 'string' && value.trim()) {
      return value.trim();
    }
  }
};

const pushIssue = (issues: ParseIssue[], path: string, message: string) => {
  issues.push({ path, message });
};

const normalizeUrl = (value: string): string => {
  const trimmed = value.trim();
  if (/^[a-z][a-z0-9+.-]*:/i.test(trimmed)) {
    return trimmed;
  }
  if (trimmed.startsWith('www.')) {
    return `https://${trimmed}`;
  }
  return trimmed;
};

const looksLikeUrl = (value: string): boolean => {
  const trimmed = value.trim();
  return /^[a-z][a-z0-9+.-]*:/i.test(trimmed) || trimmed.startsWith('www.');
};

const deriveNameFromUrl = (value: string): string => {
  const normalized = normalizeUrl(value);
  try {
    const url = new URL(normalized);
    const hostname = url.hostname.replace(/^www\./, '');
    const pathName = url.pathname.replace(/\/$/, '');
    if (pathName && pathName !== '/') {
      return `${hostname}${pathName}`;
    }
    return hostname || normalized;
  } catch {
    return normalized;
  }
};

const normalizeTags = (value: unknown): string[] | undefined => {
  if (Array.isArray(value)) {
    const tags = value
      .map((tag) => String(tag).trim())
      .filter(Boolean);
    return tags.length > 0 ? tags : undefined;
  }

  if (typeof value === 'string') {
    const tags = value
      .split(',')
      .map((tag) => tag.trim())
      .filter(Boolean);
    return tags.length > 0 ? tags : undefined;
  }
};

const isMetadataOnlyKey = (key: string): boolean =>
  LINK_NAME_KEYS.includes(key) ||
  LINK_URL_KEYS.includes(key) ||
  LINK_DESCRIPTION_KEYS.includes(key) ||
  key === 'private' ||
  key === 'tags' ||
  key === 'tag';

const isLikelyLinkRecord = (record: InputRecord): boolean => {
  if (hasUrlKey(record)) {
    return true;
  }

  const keys = Object.keys(record);
  if (keys.length === 0) {
    return false;
  }

  if (keys.every((key) => isMetadataOnlyKey(key))) {
    return true;
  }

  if (keys.length === 1) {
    return isMetadataOnlyKey(keys[0]);
  }

  return false;
};

const hasUrlKey = (record: InputRecord): boolean => LINK_URL_KEYS.some((key) => key in record);

const parseLinkShorthand = (
  value: string,
  fallbackName: string | undefined,
  issues: ParseIssue[],
  issuePath: string
): Link | null => {
  const trimmed = value.trim();
  if (!trimmed) {
    pushIssue(issues, issuePath, 'Expected a URL or link shorthand, but found an empty string.');
    return null;
  }

  if (looksLikeUrl(trimmed)) {
    return {
      name: fallbackName || deriveNameFromUrl(trimmed),
      url: normalizeUrl(trimmed),
    };
  }

  const patterns = [
    /^(.*?)\s*(?:->|=>|\|)\s*(\S+)$/,
    /^(.*?)\s*:\s*(\S+)$/,
    /^(.*?)\s+(\S+)$/,
  ];

  for (const pattern of patterns) {
    const match = trimmed.match(pattern);
    if (!match) {
      continue;
    }

    const [, rawName, rawUrl] = match;
    if (!looksLikeUrl(rawUrl)) {
      continue;
    }

    return {
      name: rawName.trim() || fallbackName || deriveNameFromUrl(rawUrl),
      url: normalizeUrl(rawUrl),
    };
  }

  if (fallbackName) {
    pushIssue(
      issues,
      issuePath,
      `Expected a URL for '${fallbackName}', but got '${trimmed}'. Use a full URL or '<name> -> <url>'.`
    );
    return null;
  }

  pushIssue(issues, issuePath, `Expected a URL or '<name> -> <url>' entry, but got '${trimmed}'.`);
  return null;
};

const toLink = (name: string, url: string, record?: InputRecord): Link => ({
  name: name.trim(),
  url: normalizeUrl(url),
  private: typeof record?.private === 'boolean' ? record.private : undefined,
  tags: normalizeTags(record?.tags ?? record?.tag),
  description: getFirstString(record || {}, LINK_DESCRIPTION_KEYS),
});

const parseLinkEntry = (
  entry: unknown,
  fallbackName: string | undefined,
  issues: ParseIssue[],
  issuePath: string
): Link[] => {
  if (typeof entry === 'string') {
    const parsed = parseLinkShorthand(entry, fallbackName, issues, issuePath);
    return parsed ? [parsed] : [];
  }

  if (entry === null || entry === undefined) {
    pushIssue(issues, issuePath, 'Link entry is empty. Expected a URL or link object.');
    return [];
  }

  if (Array.isArray(entry)) {
    pushIssue(issues, issuePath, 'Link entry cannot be a list. Put lists inside a category or under the reserved root key \'links\'.');
    return [];
  }

  if (!isRecord(entry)) {
    pushIssue(issues, issuePath, `Unsupported link entry type '${typeof entry}'. Expected a string or object.`);
    return [];
  }

  const explicitName = getFirstString(entry, LINK_NAME_KEYS) || fallbackName;
  const explicitUrl = getFirstString(entry, LINK_URL_KEYS);
  const entryKeys = Object.keys(entry);

  if (explicitName && explicitUrl) {
    return [toLink(explicitName, explicitUrl, entry)];
  }

  if (!explicitName && explicitUrl) {
    return [toLink(deriveNameFromUrl(explicitUrl), explicitUrl, entry)];
  }

  if (entryKeys.length > 0 && entryKeys.every((key) => isMetadataOnlyKey(key))) {
    pushIssue(
      issues,
      issuePath,
      `Link '${fallbackName || issuePath}' is missing a URL. Use one of ${LINK_URL_KEYS.join(', ')}.`
    );
    return [];
  }

  if (entryKeys.length === 1) {
    const [key, value] = Object.entries(entry)[0];
    return parseLinkEntry(value, key, issues, `${issuePath}.${key}`);
  }

  const links: Link[] = [];

  for (const [key, value] of Object.entries(entry)) {
    if (isMetadataOnlyKey(key)) {
      continue;
    }

    links.push(...parseLinkEntry(value, key, issues, `${issuePath}.${key}`));
  }

  if (links.length === 0) {
    pushIssue(
      issues,
      issuePath,
      `Could not understand this link object. Expected one of ${LINK_URL_KEYS.join(', ')} or a single '<name>: <url>' entry.`
    );
  }

  return links;
};

const parseLinksCollection = (value: unknown, issues: ParseIssue[], issuePath: string): Link[] => {
  if (Array.isArray(value)) {
    return value.flatMap((entry, index) => parseLinkEntry(entry, undefined, issues, `${issuePath}[${index}]`));
  }

  if (isRecord(value)) {
    return Object.entries(value).flatMap(([key, entry]) =>
      parseLinkEntry(entry, key, issues, `${issuePath}.${key}`)
    );
  }

  if (typeof value === 'string') {
    return parseLinkEntry(value, undefined, issues, issuePath);
  }

  pushIssue(
    issues,
    issuePath,
    `Expected a list of links, a map of links, or a link string. Got '${typeof value}' instead.`
  );
  return [];
};

const parseCategory = (
  name: string,
  value: unknown,
  issues: ParseIssue[],
  issuePath: string,
  allowSingleLink = true
): Category | null => {
  if (value === null || value === undefined) {
    pushIssue(issues, issuePath, `Category '${name}' is empty.`);
    return null;
  }

  let description: string | undefined;
  let links: Link[] = [];

  if (Array.isArray(value)) {
    links = parseLinksCollection(value, issues, issuePath);
  } else if (isRecord(value)) {
    description = getFirstString(value, CATEGORY_DESCRIPTION_KEYS);

    for (const key of LINK_COLLECTION_KEYS) {
      if (key in value) {
        links.push(...parseLinksCollection(value[key], issues, `${issuePath}.${key}`));
      }
    }

    const directEntries = Object.entries(value).filter(([key]) => {
      if (CATEGORY_NAME_KEYS.includes(key) || CATEGORY_DESCRIPTION_KEYS.includes(key)) {
        return false;
      }
      if (LINK_COLLECTION_KEYS.includes(key)) {
        return false;
      }
      return true;
    });

    links.push(
      ...directEntries.flatMap(([key, entry]) => parseLinkEntry(entry, key, issues, `${issuePath}.${key}`))
    );
  } else if (typeof value === 'string') {
    if (!allowSingleLink) {
      pushIssue(
        issues,
        issuePath,
        `Top-level category '${name}' must be a map or list of links. For a single link, move it to the root as '<name>: <url>'.`
      );
      return null;
    }
    links = parseLinkEntry(value, name, issues, issuePath);
  } else {
    pushIssue(
      issues,
      issuePath,
      `Category '${name}' has unsupported type '${typeof value}'. Expected a map, list, or URL string.`
    );
    return null;
  }

  if (links.length === 0) {
    pushIssue(issues, issuePath, `Category '${name}' does not contain any valid links.`);
    return null;
  }

  return {
    category: name,
    description,
    links,
  };
};

const parseCategoryEntry = (
  entry: unknown,
  fallbackName: string | undefined,
  issues: ParseIssue[],
  issuePath: string
): Category[] => {
  if (!isRecord(entry)) {
    pushIssue(issues, issuePath, 'Category entry must be an object.');
    return [];
  }

  const explicitName = getFirstString(entry, CATEGORY_NAME_KEYS) || fallbackName;
  if (explicitName) {
    const category = parseCategory(explicitName, entry, issues, issuePath, false);
    return category ? [category] : [];
  }

  if (Object.keys(entry).length === 1) {
    const [key, value] = Object.entries(entry)[0];
    const category = parseCategory(key, value, issues, `${issuePath}.${key}`, false);
    return category ? [category] : [];
  }

  pushIssue(
    issues,
    issuePath,
    `Could not determine the category name. Use one of ${CATEGORY_NAME_KEYS.join(', ')}.`
  );
  return [];
};

const parseCategoriesContainer = (value: unknown, issues: ParseIssue[], issuePath: string): Category[] => {
  if (Array.isArray(value)) {
    return value.flatMap((entry, index) => parseCategoryEntry(entry, undefined, issues, `${issuePath}[${index}]`));
  }

  if (isRecord(value)) {
    return Object.entries(value).flatMap(([key, entry]) => {
      const category = parseCategory(key, entry, issues, `${issuePath}.${key}`, false);
      return category ? [category] : [];
    });
  }

  pushIssue(
    issues,
    issuePath,
    `Expected a categories container to be a list or map. Got '${typeof value}' instead.`
  );
  return [];
};

const parseRootLinks = (root: InputRecord, issues: ParseIssue[]): Link[] => {
  const links: Link[] = [];

  for (const [key, value] of Object.entries(root)) {
    if (RESERVED_ROOT_KEYS.has(key) || CATEGORY_CONTAINER_KEYS.includes(key)) {
      continue;
    }

    if (typeof value === 'string') {
      links.push(...parseLinkEntry(value, key, issues, key));
      continue;
    }

    if (isRecord(value) && isLikelyLinkRecord(value)) {
      links.push(...parseLinkEntry(value, key, issues, key));
    }
  }

  return links;
};

const isRootLinkEntry = (value: unknown): boolean =>
  typeof value === 'string' || (isRecord(value) && isLikelyLinkRecord(value));

const resolveDefaultYamlPath = (): string => {
  const cwd = process.cwd();
  const directCandidates = ['portal.yml', 'portal.yaml'];

  for (const candidate of directCandidates) {
    const candidatePath = path.resolve(cwd, candidate);
    if (fs.existsSync(candidatePath)) {
      return candidatePath;
    }
  }

  const portalCandidates = fs
    .readdirSync(cwd)
    .filter((file) => /^.+\.portal\.ya?ml$/i.test(file))
    .sort();

  if (portalCandidates.length === 1) {
    return path.resolve(cwd, portalCandidates[0]);
  }

  return path.resolve(cwd, 'portal.yml');
};

/**
 * Displays the help message for the portal CLI tool and exits the process.
 */
const showHelp = () => {
  console.log(`
Usage: portal [path/to/your/portal.yml] [options]

portal is a command-line tool that generates a beautiful HTML index page
from a forgiving YAML configuration file.

Arguments:
  [path/to/your/portal.yml]  Optional. Path to the YAML configuration file.
                              Defaults to portal.yml, portal.yaml, or the only
                              *.portal.yml file in the current directory.

Options:
  -h, --help                  Display this help message.
  -o, --outfile <path>        Specify the output path for the generated HTML file.
                              Defaults to 'index.html' in the YAML file's directory.

Examples:
  portal
  portal my_custom_config.yml
  portal -o output.html
  portal my_custom_config.yml -o /tmp/my_portal.html
  portal -h

Accepted portal syntaxes:
  title: My Portal
  Docs: https://docs.example.com

  Development:
    Docs: https://docs.example.com

  Development:
    - Docs: https://docs.example.com
    - name: Dashboard
      url: https://dashboard.example.com

  categories:
    - category: Development
      links:
        - Docs -> https://docs.example.com
`);
  process.exit(0);
};

/**
 * Parses command-line arguments to determine the YAML config path and HTML output path.
 * @returns {{ yamlPath: string, outputPath: string }} An object containing the paths.
 */
const parseArgs = (): { yamlPath: string; outputPath: string } => {
  const args = process.argv.slice(2);
  let yamlPath: string | undefined;
  let outputPath: string | undefined;

  for (let i = 0; i < args.length; i++) {
    const arg = args[i];
    switch (arg) {
      case '-h':
      case '--help':
        showHelp();
        break;
      case '-o':
      case '--outfile':
        if (i + 1 < args.length) {
          outputPath = path.resolve(args[++i]);
        } else {
          console.error('Error: --outfile requires a path argument.');
          process.exit(1);
        }
        break;
      default:
        if (!yamlPath) {
          yamlPath = path.resolve(arg);
        } else {
          console.error(`Error: Unexpected argument: ${arg}`);
          process.exit(1);
        }
        break;
    }
  }

  const finalYamlPath = yamlPath || resolveDefaultYamlPath();
  const finalOutputPath = outputPath || path.resolve(path.dirname(finalYamlPath), 'index.html');

  return { yamlPath: finalYamlPath, outputPath: finalOutputPath };
};

/**
 * Loads and parses a YAML file from the given path.
 * @param {string} filePath - The absolute path to the YAML file.
 * @returns {Config} The parsed YAML configuration.
 * @throws {Error} If the file cannot be read or parsed.
 */
const loadYaml = (filePath: string): Config => {
  try {
    const fileContents = fs.readFileSync(filePath, 'utf8');
    const loadedYaml = yaml.load(fileContents) as any;

    if (!loadedYaml || typeof loadedYaml !== 'object') {
      throw new Error('Root YAML value must be a map.');
    }

    const root = loadedYaml as InputRecord;
    const issues: ParseIssue[] = [];
    const categories: Category[] = [];
    const rootLinks: Link[] = [];
    let rootLinksCategory: Category | null = null;

    if ('links' in root) {
      pushIssue(
        issues,
        'links',
        'Root-level \'links\' is no longer supported. Move those entries to the root as \'<name>: <url>\' entries or put them inside a category.'
      );
    }

    for (const [key, value] of Object.entries(root)) {
      if (key === 'title' || key === 'name' || key === 'description') {
        continue;
      }

      if (key === 'links') {
        continue;
      }

      if (CATEGORY_CONTAINER_KEYS.includes(key)) {
        categories.push(...parseCategoriesContainer(value, issues, key));
        continue;
      }

      if (isRootLinkEntry(value)) {
        if (!rootLinksCategory) {
          rootLinksCategory = {
            category: ROOT_LINKS_CATEGORY,
            links: rootLinks,
          };
          categories.push(rootLinksCategory);
        }
        rootLinks.push(...parseLinkEntry(value, key, issues, key));
        continue;
      }

      const category = parseCategory(key, value, issues, key, false);
      if (category) {
        categories.push(category);
      }
    }

    if (categories.length === 0 && issues.length === 0) {
      pushIssue(
        issues,
        'root',
        'No links or categories were found. Add root-level links or category sections.'
      );
    }

    if (issues.length > 0) {
      const formattedIssues = issues.map((issue) => `  - ${issue.path}: ${issue.message}`).join('\n');
      throw new Error(`Invalid portal file '${filePath}':\n${formattedIssues}`);
    }

    return { title: typeof root.title === 'string' ? root.title : undefined, categories };
  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    console.error(`Error loading or parsing YAML file:\n${message}`);
    process.exit(1);
  }
};

/**
 * Generates a favicon URL for a given website URL using Google's favicon service.
 * @param {string} url - The URL of the website.
 * @returns {string} The URL of the favicon, or an empty string if the input URL is invalid.
 */
const getFaviconUrl = (url: string): string => {
  try {
    const urlObj = new URL(url);
    return `https://www.google.com/s2/favicons?domain=${urlObj.hostname}`;
  } catch (e) {
    console.warn(`Invalid URL for favicon: ${url}`);
    return '';
  }
};

/**
 * Generates the HTML content for the portal page based on the provided configuration.
 * @param {Config} config - The configuration object containing projects and links.
 * @returns {Promise<string>} A promise that resolves to the generated HTML string.
 */
const generateHtml = async (config: Config): Promise<string> => {
  const categoriesHtmlPromises = config.categories
    .map(async (category) => {
      const linksHtmlPromises = category.links
        .map(async (link) => {
          const faviconUrl = getFaviconUrl(link.url);
          return `<a href="${link.url}" class="link-card" target="_blank" rel="noopener noreferrer">
                    <div class="link-card-content">
                      <div class="link-card-main">
                        <div class="link-card-title-group">
                          ${faviconUrl ? `<img src="${faviconUrl}" alt="" width="16" height="16">` : ''}
                          <span>${link.name}</span>
                        </div>
                        ${link.private ? '<span class="private-icon"> 🔒</span>' : ''}
                      </div>
                      ${link.description ? `<div class="link-description">${link.description}</div>` : ''}
                      ${link.tags && link.tags.length > 0 ? `<div class="link-tag-container">${link.tags.map(tag => `<span class="link-tag">${tag}</span>`).join('')}</div>` : ''}
                    </div>
                  </a>`;
        });
      const linksHtml = (await Promise.all(linksHtmlPromises)).join('');

      return `
        <div class="category-card">
            <h3>${category.category}</h3>
            ${category.description ? `<p>${category.description}</p>` : ''}
            <div class="links-container">
                ${linksHtml}
            </div>
        </div>`;
    });
  const categoriesHtml = (await Promise.all(categoriesHtmlPromises)).join('');

  return `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${config.title || '🚪 Portal'}</title>
    <style>
        @font-face {
            font-family: 'GohuFont';
            src: url('data:font/truetype;charset=utf-8;base64,') format('truetype');
        }

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: 'GohuFont', monospace;
        }

        body {
            background-color: #000000;
            color: #ffffff;
            padding: 20px;
            line-height: 1.6;
        }

        .container {
            max-width: 1200px;
            margin: 0 auto;
        }

        h1 {
            font-size: 1.5rem;
            margin-bottom: 20px;
            border-bottom: 1px solid #ffffff;
            padding-bottom: 10px;
        }

        h3 {
            font-size: 1.2rem;
            margin-bottom: 15px;
            font-weight: normal;
        }

        .category-card {
            margin-bottom: 30px;
            padding-bottom: 30px;
            border-bottom: 1px solid #ffffff;
        }

        .category-card:last-child {
            border-bottom: none;
        }

        .links-container {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
            gap: 10px;
        }

        .link-card {
            background-color: #000000;
            border: 1px solid #ffffff;
            padding: 10px;
            text-decoration: none;
            color: #ffffff;
            display: block;
            transition: background-color 0.2s, color 0.2s;
        }

        .link-card:hover {
            background-color: #ffffff;
            color: #000000;
        }

        .link-card-content {
            display: flex;
            flex-direction: column;
            gap: 5px;
        }

        .link-card-main {
            display: flex;
            align-items: center;
            justify-content: space-between;
        }

        .link-card-title-group {
            display: flex;
            align-items: center;
            gap: 8px;
        }

        .link-card img {
            width: 16px;
            height: 16px;
            filter: invert(1);
        }

        .link-card:hover img {
            filter: invert(0);
        }

        .private-icon {
            font-size: 0.8em;
            border: 1px solid #ffffff;
            padding: 2px 6px;
        }

        .link-card:hover .private-icon {
            border-color: #000000;
        }

        .link-description {
            font-size: 0.85em;
            opacity: 0.8;
        }

        .link-tag-container {
            display: flex;
            gap: 5px;
            flex-wrap: wrap;
        }

        .link-tag {
            font-size: 0.75em;
            border: 1px solid #ffffff;
            padding: 2px 8px;
        }

        .link-card:hover .link-tag {
            border-color: #000000;
        }

        .filters {
            display: flex;
            gap: 10px;
            margin-bottom: 20px;
            flex-wrap: wrap;
        }

        .filters input[type="text"],
        .filters select {
            padding: 8px;
            border: 1px solid #ffffff;
            background-color: #000000;
            color: #ffffff;
            flex: 1;
            min-width: 200px;
        }

        .filters input[type="text"]:focus,
        .filters select:focus {
            outline: none;
            background-color: #ffffff;
            color: #000000;
        }

        .filters input[type="text"]::placeholder {
            color: #888888;
        }

        @media (max-width: 768px) {
            .links-container {
                grid-template-columns: 1fr;
            }
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>${config.title || '🚪 Portal'}</h1>
        <div class="filters">
            <input type="text" id="search-bar" placeholder="Search links...">
            <select id="tag-filter">
                <option value="">All Tags</option>
                ${[...new Set(config.categories.flatMap(c => c.links).flatMap(l => l.tags || []).filter(Boolean))].map(tag => `<option value="${tag}">${tag}</option>`).join('')}
            </select>
        </div>
        <div id="categories">
            ${categoriesHtml}
        </div>
    </div>
    <script>
        const searchBar = document.getElementById('search-bar');
        const tagFilter = document.getElementById('tag-filter');
        const categoryCards = document.querySelectorAll('.category-card');

        function filterLinks() {
            const searchTerm = searchBar.value.toLowerCase();
            const selectedTag = tagFilter.value;

            categoryCards.forEach(categoryCard => {
                let categoryHasVisibleLinks = false;
                const linksContainer = categoryCard.querySelector('.links-container');
                const linkCards = linksContainer ? linksContainer.querySelectorAll('.link-card') : [];

                linkCards.forEach(linkCard => {
                    const linkName = linkCard.querySelector('.link-card-main').textContent.toLowerCase();
                    const linkTags = Array.from(linkCard.querySelectorAll('.link-tag')).map(el => el.textContent);

                    const matchesSearch = linkName.includes(searchTerm);
                    const matchesTag = selectedTag === '' || linkTags.includes(selectedTag);

                    if (matchesSearch && matchesTag) {
                        linkCard.style.display = 'block';
                        categoryHasVisibleLinks = true;
                    } else {
                        linkCard.style.display = 'none';
                    }
                });

                if (categoryHasVisibleLinks) {
                    categoryCard.style.display = 'block';
                } else {
                    categoryCard.style.display = 'none';
                }
            });
        }

        searchBar.addEventListener('input', filterLinks);
        tagFilter.addEventListener('change', filterLinks);
    </script>
</body>
</html>`;
};

/**
 * Main function to run the portal application.
 * It determines the YAML file path, creates a default one if it doesn't exist,
 * loads the configuration, generates HTML, and writes it to 'index.html'.
 */
const main = async () => {
  const { yamlPath, outputPath } = parseArgs();

  if (!fs.existsSync(yamlPath)) {
    if (yamlPath.endsWith('portal.yml') || yamlPath.endsWith('portal.yaml')) {
      const defaultConfig = {
        title: 'Portal',
        Development: [
          { Docs: 'https://docs.example.com' },
          { Dashboard: 'https://dashboard.example.com' },
          {
            Repo: {
              url: 'https://github.com/example/repo',
              tags: ['code'],
            },
          },
        ],
      };
      fs.writeFileSync(yamlPath, yaml.dump(defaultConfig), 'utf8');
    } else {
      console.error(`Error: YAML file not found at ${yamlPath}`);
      process.exit(1);
    }
  }

  const config = loadYaml(yamlPath);
  const htmlContent = await generateHtml(config);
  fs.writeFileSync(outputPath, htmlContent, 'utf8');
  console.log(`Successfully created ${outputPath}`);
};

main();
